import React, { useState } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  SafeAreaView, 
  TouchableOpacity, 
  ScrollView, 
  FlatList,
  Alert
} from 'react-native';
import * as ImagePicker from 'expo-image-picker';
import { useStore } from '../store/useStore';
import { UtilityType, Receipt, ExtractedData } from '../types';
import { parseReceiptText } from '../services/parserService';
import VerifyModal from '../components/VerifyModal';
import { LineChart, Grid, YAxis, XAxis } from 'react-native-svg-charts';

export default function DashboardScreen() {
  const { receipts, addReceipt, deleteReceipt } = useStore();
  const [activeTab, setActiveTab] = useState<UtilityType>(UtilityType.ELECTRIC);
  const [isScanning, setIsScanning] = useState(false);
  const [scannedData, setScannedData] = useState<ExtractedData | null>(null);
  const [showVerify, setShowVerify] = useState(false);

  const filteredReceipts = receipts.filter(r => r.utility_type === activeTab);

  const handleScan = async () => {
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      quality: 1,
    });

    if (!result.canceled) {
      setIsScanning(true);
      // Simulation of OCR - we will integrate actual OCR later
      // For now, using a mock result for testing
      setTimeout(() => {
        const mockExtracted: ExtractedData = {
          total: 2590.16,
          consumption: 243,
          date: '2026-03-01',
          utilityType: activeTab
        };
        setScannedData(mockExtracted);
        setShowVerify(true);
        setIsScanning(false);
      }, 2000);
    }
  };

  const handleConfirm = (data: ExtractedData) => {
    addReceipt({
      total_amount: data.total,
      consumption_kwh: data.consumption,
      billing_date: data.date,
      utility_type: data.utilityType || activeTab,
      user_id: 'mock-user'
    });
    setShowVerify(false);
  };

  const chartData = [10, 20, 15, 30, 25, 40]; // Placeholder

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>Resibo</Text>
        <View style={styles.tabContainer}>
          <TouchableOpacity 
            style={[styles.tab, activeTab === UtilityType.ELECTRIC && styles.activeTab]}
            onPress={() => setActiveTab(UtilityType.ELECTRIC)}
          >
            <Text style={[styles.tabText, activeTab === UtilityType.ELECTRIC && styles.activeTabText]}>Electric</Text>
          </TouchableOpacity>
          <TouchableOpacity 
            style={[styles.tab, activeTab === UtilityType.WATER && styles.activeTab]}
            onPress={() => setActiveTab(UtilityType.WATER)}
          >
            <Text style={[styles.tabText, activeTab === UtilityType.WATER && styles.activeTabText]}>Water</Text>
          </TouchableOpacity>
        </View>
      </View>

      <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={styles.scrollContent}>
        <View style={styles.summaryContainer}>
          <View style={styles.card}>
            <Text style={styles.cardLabel}>Current Month</Text>
            <Text style={styles.cardValue}>₱0.00</Text>
          </View>
          <View style={[styles.card, styles.tealCard]}>
            <Text style={styles.cardLabel}>Total Usage</Text>
            <Text style={styles.cardValue}>0 <Text style={styles.unit}>{activeTab === UtilityType.ELECTRIC ? 'kWh' : 'm³'}</Text></Text>
          </View>
        </View>

        <View style={styles.chartSection}>
          <Text style={styles.sectionTitle}>Usage Trends</Text>
          <View style={styles.chartContainer}>
            <LineChart
              style={{ height: 200 }}
              data={chartData}
              svg={{ stroke: '#2563EB', strokeWidth: 3 }}
              contentInset={{ top: 20, bottom: 20 }}
            >
              <Grid />
            </LineChart>
          </View>
        </View>

        <View style={styles.historySection}>
          <Text style={styles.sectionTitle}>Recent History</Text>
          {filteredReceipts.length === 0 ? (
            <View style={styles.emptyState}>
              <Text style={styles.emptyText}>No receipts found yet.</Text>
            </View>
          ) : (
            filteredReceipts.map(receipt => (
              <View key={receipt.id} style={styles.receiptItem}>
                <View>
                  <Text style={styles.receiptDate}>{receipt.billing_date}</Text>
                  <Text style={styles.receiptAmount}>₱{receipt.total_amount.toLocaleString()}</Text>
                </View>
                <Text style={styles.receiptCons}>{receipt.consumption_kwh} {receipt.utility_type === UtilityType.ELECTRIC ? 'kWh' : 'm³'}</Text>
              </View>
            ))
          )}
        </View>
      </ScrollView>

      <TouchableOpacity style={styles.scanButton} onPress={handleScan} disabled={isScanning}>
        <Text style={styles.scanButtonText}>{isScanning ? 'Scanning...' : 'Scan Receipt'}</Text>
      </TouchableOpacity>

      <VerifyModal 
        visible={showVerify} 
        data={scannedData} 
        onConfirm={handleConfirm}
        onCancel={() => setShowVerify(false)}
      />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F8FAFC',
  },
  header: {
    padding: 20,
    backgroundColor: '#fff',
    borderBottomWidth: 1,
    borderBottomColor: '#E2E8F0',
  },
  headerTitle: {
    fontSize: 24,
    fontWeight: 'bold',
    color: '#0F172A',
    marginBottom: 16,
  },
  tabContainer: {
    flexDirection: 'row',
    backgroundColor: '#F1F5F9',
    borderRadius: 12,
    padding: 4,
  },
  tab: {
    flex: 1,
    paddingVertical: 10,
    alignItems: 'center',
    borderRadius: 8,
  },
  activeTab: {
    backgroundColor: '#fff',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.05,
    shadowRadius: 4,
    elevation: 2,
  },
  tabText: {
    fontSize: 14,
    fontWeight: '600',
    color: '#64748B',
  },
  activeTabText: {
    color: '#2563EB',
  },
  scrollContent: {
    padding: 20,
    paddingBottom: 100,
  },
  summaryContainer: {
    flexDirection: 'row',
    gap: 16,
    marginBottom: 24,
  },
  card: {
    flex: 1,
    backgroundColor: '#fff',
    padding: 16,
    borderRadius: 20,
    borderWidth: 1,
    borderColor: '#E2E8F0',
  },
  tealCard: {
    backgroundColor: '#F0FDFA',
    borderColor: '#CCFBF1',
  },
  cardLabel: {
    fontSize: 12,
    color: '#64748B',
    marginBottom: 4,
    fontWeight: '600',
  },
  cardValue: {
    fontSize: 20,
    fontWeight: 'bold',
    color: '#0F172A',
  },
  unit: {
    fontSize: 14,
    fontWeight: 'normal',
    color: '#64748B',
  },
  chartSection: {
    marginBottom: 24,
  },
  sectionTitle: {
    fontSize: 18,
    fontWeight: 'bold',
    color: '#0F172A',
    marginBottom: 16,
  },
  chartContainer: {
    backgroundColor: '#fff',
    padding: 16,
    borderRadius: 20,
    borderWidth: 1,
    borderColor: '#E2E8F0',
  },
  historySection: {
    marginBottom: 24,
  },
  emptyState: {
    backgroundColor: '#fff',
    padding: 40,
    borderRadius: 20,
    borderWidth: 1,
    borderColor: '#E2E8F0',
    borderStyle: 'dashed',
    alignItems: 'center',
  },
  emptyText: {
    color: '#94A3B8',
  },
  receiptItem: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    backgroundColor: '#fff',
    padding: 16,
    borderRadius: 16,
    marginBottom: 12,
    borderWidth: 1,
    borderColor: '#E2E8F0',
  },
  receiptDate: {
    fontSize: 14,
    fontWeight: '600',
    color: '#0F172A',
  },
  receiptAmount: {
    fontSize: 12,
    color: '#64748B',
    marginTop: 2,
  },
  receiptCons: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#0D9488',
  },
  scanButton: {
    position: 'absolute',
    bottom: 30,
    left: 20,
    right: 20,
    backgroundColor: '#2563EB',
    padding: 18,
    borderRadius: 20,
    alignItems: 'center',
    shadowColor: '#2563EB',
    shadowOffset: { width: 0, height: 10 },
    shadowOpacity: 0.3,
    shadowRadius: 20,
    elevation: 8,
  },
  scanButtonText: {
